function getFilters(){return{searchTerm:document.getElementById("searchTerm").value,categories:Array.from(document.querySelectorAll(".category-checkbox:checked")).map(n=>n.value).join(","),levels:Array.from(document.querySelectorAll(".level-checkbox:checked")).map(n=>n.value).join(","),minWords:document.getElementById("minWordCount").value,maxWords:document.getElementById("maxWordCount").value}}async function loadBundles(n=1){const t=getFilters(),i=new URLSearchParams({page:n,pageSize:parseInt(document.getElementById("bundles-list-container").dataset.pageSize,10)||6,search:t.searchTerm,categoryFilter:t.categories,levelFilter:t.levels,minWordCount:t.minWords,maxWordCount:t.maxWords});try{const n=await fetch(`/Bundle/Index?${i.toString()}`,{headers:{"X-Requested-With":"XMLHttpRequest"}});if(n.ok){const t=await n.text();document.getElementById("bundles-list-container").innerHTML=t}}catch(r){console.error(r)}}function onFilterChange(){loadBundles(1)}function debounceSearch(){clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>onFilterChange(),500)}function changePage(n){loadBundles(n);window.scrollTo({top:0,behavior:"smooth"})}function submitForReview(n,t="this collection"){confirm(`Are you sure? After sending for review you will not be able to edit the collection "${t}" until the admin approves it.`)&&submitBundle(n)}async function submitBundle(n){const t=document.querySelector('input[name="__RequestVerificationToken"]').value;if(!t){console.error("Verification token not found");return}try{const i=await fetch(`/Bundle/SubmitForReview/${n}`,{method:"POST",headers:{"X-CSRF-TOKEN":t,"X-Requested-With":"XMLHttpRequest"}});if(i.ok){const n=await i.json();showToast(n.message);loadBundles()}else{let n="Error submitting collection.";try{const t=await i.json();n=t.message||n}catch(r){}showToast(n,"danger")}}catch(i){console.error(i);showToast("An unexpected error occurred.","danger")}}let searchTimeout;document.getElementById("categorySearch").addEventListener("input",function(){const n=this.value.toLowerCase().trim(),t=document.querySelectorAll("#category-filters .checkbox-item");t.forEach(t=>{const i=t.querySelector("label"),r=i.textContent.toLowerCase();t.style.display=n===""||r.includes(n)?"":"none"})});